const DateTime = require('luxon').DateTime;
const now = DateTime.now().setZone('Europe/Berlin');
const currentDate = now.toFormat('yyyy-MM-dd');

const msg = $input.first().json.message || {};
const chatId = String(msg.chat?.id || '6023241557');
const sessionKey = chatId + '_' + currentDate;

let messageText = msg.text || msg.caption || '';
const hasPhoto = !!(msg.photo && msg.photo.length > 0);
const hasVoice = !!(msg.voice || msg.audio);

return [{
  json: {
    currentDate,
    chatId,
    sessionKey,
    messageText,
    hasPhoto,
    hasVoice
  }
}];

const messageData = $("Get Current Date").first().json;
const logData = $("Fetch Today Food Log").all();

let result = {
  currentDate: messageData.currentDate,
  chatId: messageData.chatId,
  sessionKey: messageData.sessionKey,
  hasPhoto: messageData.hasPhoto,
  hasVoice: messageData.hasVoice,
  messageText: messageData.messageText || "",
  total_calories: 0,
  total_protein: 0,
  total_carbs: 0,
  total_fat: 0,
  meals_log: "",
  workout: null,
  steps_10k: null,
  reading: null,
  supplements: null,
  mindfulness: null,
  sleep_quality: null,
  userInput: ""
};

if (logData.length > 0 && logData[0].json.date) {
  const log = logData[0].json;
  result.total_calories = log.total_calories || 0;
  result.total_protein = log.total_protein || 0;
  result.total_carbs = log.total_carbs || 0;
  result.total_fat = log.total_fat || 0;
  result.meals_log = log.meals_log || "";
  result.workout = log.workout || null;
  result.steps_10k = log.steps_10k || null;
  result.reading = log.reading || null;
  result.supplements = log.supplements || null;
  result.mindfulness = log.mindfulness || null;
  result.sleep_quality = log.sleep_quality || null;
}

if (result.hasPhoto && result.messageText) {
  result.userInput = result.messageText + " (see attached food photo)";
} else if (result.hasPhoto) {
  result.userInput = "I ate this (see attached photo)";
} else if (result.hasVoice) {
  result.userInput = "(Voice note received - please type your meal instead, voice transcription coming soon)";
} else {
  result.userInput = result.messageText;
}

let binary = {};
try { binary = $("Telegram Trigger").first().binary || {}; } catch(e) {}

return [{ json: result, binary: binary }];

const agentOutput = $input.first().json;
const preparedData = $("Prepare AI Input").first().json;

let response = "";
if (agentOutput.output) {
  response = agentOutput.output;
} else if (typeof agentOutput === "string") {
  response = agentOutput;
} else {
  response = JSON.stringify(agentOutput);
}

const dataMatch = response.match(/<!-- DATA:(.*?) -->/s);
let data = null;
let cleanResponse = response;

if (dataMatch) {
  try {
    data = JSON.parse(dataMatch[1]);
  } catch(e) {
    data = null;
  }
  cleanResponse = response.replace(/<!-- DATA:.*? -->/s, "").trim();
}

const result = {
  ai_response: cleanResponse,
  date: preparedData.currentDate,
  chat_id: preparedData.chatId,
  hasDataToSave: false,
  total_calories: preparedData.total_calories || 0,
  total_protein: preparedData.total_protein || 0,
  total_carbs: preparedData.total_carbs || 0,
  total_fat: preparedData.total_fat || 0,
  meals_log: preparedData.meals_log || "",
  workout: preparedData.workout || null,
  steps_10k: preparedData.steps_10k || null,
  reading: preparedData.reading || null,
  supplements: preparedData.supplements || null,
  mindfulness: preparedData.mindfulness || null,
  sleep_quality: preparedData.sleep_quality || null
};

if (data && data.type === "food") {
  result.hasDataToSave = true;
  const mc = Number(data.calories) || 0;
  const mp = Number(data.protein) || 0;
  const mca = Number(data.carbs) || 0;
  const mf = Number(data.fat) || 0;
  const mn = data.meal || "Unknown";
  result.total_calories = (preparedData.total_calories || 0) + mc;
  result.total_protein = (preparedData.total_protein || 0) + mp;
  result.total_carbs = (preparedData.total_carbs || 0) + mca;
  result.total_fat = (preparedData.total_fat || 0) + mf;
  const entry = mn + " (" + mc + " kcal, " + mp + "g P)";
  result.meals_log = preparedData.meals_log ? preparedData.meals_log + "; " + entry : entry;
} else if (data && data.type === "reset") {
  result.hasDataToSave = true;
  result.total_calories = 0;
  result.total_protein = 0;
  result.total_carbs = 0;
  result.total_fat = 0;
  result.meals_log = "";
} else if (data && data.type === "habits") {
  result.hasDataToSave = true;
  if (data.workout) result.workout = data.workout;
  if (data.steps_10k) result.steps_10k = data.steps_10k;
  if (data.reading) result.reading = data.reading;
  if (data.supplements) result.supplements = data.supplements;
  if (data.mindfulness) result.mindfulness = data.mindfulness;
  if (data.sleep_quality) result.sleep_quality = data.sleep_quality;
}

return [{ json: result }];

const cb = $input.first().json.callback_query;
const parts = cb.data.split(':');
const DateTime = require('luxon').DateTime;

return [{
  json: {
    habit_name: parts[1],
    habit_value: parts[2],
    chat_id: String(cb.message.chat.id),
    currentDate: parts[3] || DateTime.now().setZone('Europe/Berlin').toFormat('yyyy-MM-dd'),
    callback_query_id: cb.id,
    message_id: cb.message.message_id
  }
}];

const callback = $("Parse Callback").first().json;
const fetched = $input.first().json;

const result = {
  date: callback.currentDate,
  chat_id: callback.chat_id,
  total_calories: fetched.total_calories || 0,
  total_protein: fetched.total_protein || 0,
  total_carbs: fetched.total_carbs || 0,
  total_fat: fetched.total_fat || 0,
  meals_log: fetched.meals_log || "",
  workout: fetched.workout || null,
  steps_10k: fetched.steps_10k || null,
  reading: fetched.reading || null,
  supplements: fetched.supplements || null,
  mindfulness: fetched.mindfulness || null,
  sleep_quality: fetched.sleep_quality || null
};

const map = {
  workout: "workout",
  steps: "steps_10k",
  reading: "reading",
  supplements: "supplements",
  mindfulness: "mindfulness",
  sleep: "sleep_quality"
};
const col = map[callback.habit_name];
if (col) result[col] = callback.habit_value;

const emoji = {
  workout: "💪",
  steps: "🚶",
  reading: "📖",
  supplements: "💊",
  mindfulness: "🧘",
  sleep: "😴"
};
result.confirmation = (emoji[callback.habit_name] || "✅") + " " + callback.habit_name + ": " + (callback.habit_value === "yes" ? "✅" : "❌");
result.callback_query_id = callback.callback_query_id;

return [{ json: result }];

const DateTime = require('luxon').DateTime;
const currentDate = DateTime.now().setZone('Europe/Berlin').toFormat('yyyy-MM-dd');
return [{ json: { chat_id: '6023241557', currentDate } }];

const config = $("Evening Config").first().json;
const fetched = $input.first().json;

const cal = fetched.total_calories || 0;
const pro = fetched.total_protein || 0;
const carbs = fetched.total_carbs || 0;
const fat = fetched.total_fat || 0;

let msg = "🌙 <b>Evening Check-in</b>\n\n";
msg += "📊 <b>Today's Progress:</b>\n";
msg += "Calories: " + cal + " / 1900 kcal\n";
msg += "Protein: " + pro + "g / 170g\n";
msg += "Carbs: " + carbs + "g | Fat: " + fat + "g\n\n";
msg += "How did your habits go today? Tap below:";

const kb = {
  inline_keyboard: [
    [
      { text: "💪 Workout ✅", callback_data: "habit:workout:yes:" + config.currentDate },
      { text: "💪 Workout ❌", callback_data: "habit:workout:no:" + config.currentDate }
    ],
    [
      { text: "🚶 10k Steps ✅", callback_data: "habit:steps:yes:" + config.currentDate },
      { text: "🚶 10k Steps ❌", callback_data: "habit:steps:no:" + config.currentDate }
    ],
    [
      { text: "📖 Reading ✅", callback_data: "habit:reading:yes:" + config.currentDate },
      { text: "📖 Reading ❌", callback_data: "habit:reading:no:" + config.currentDate }
    ],
    [
      { text: "💊 Supplements ✅", callback_data: "habit:supplements:yes:" + config.currentDate },
      { text: "💊 Supplements ❌", callback_data: "habit:supplements:no:" + config.currentDate }
    ],
    [
      { text: "🧘 Mindful ✅", callback_data: "habit:mindfulness:yes:" + config.currentDate },
      { text: "🧘 Mindful ❌", callback_data: "habit:mindfulness:no:" + config.currentDate }
    ],
    [
      { text: "😴 Sleep Good", callback_data: "habit:sleep:yes:" + config.currentDate },
      { text: "😴 Sleep Bad", callback_data: "habit:sleep:no:" + config.currentDate }
    ]
  ]
};

return [{
  json: {
    chat_id: config.chat_id,
    message: msg,
    reply_markup: JSON.stringify(kb)
  }
}];
